mapper.select:
select a.insp_req_dt,
       a.insp_req_no,
       a.linecd,
       a.progcd,
       a.ordymd,
       a.proymd,
       a.lotno,
       a.itemcd,
       a.insp_ord,
       a.inspcd,
       a.insp_ser,
       a.err_type,
       b.CDNM as err_type_nm,
       a.errqty
  from pd_insp_rslt_d a
  left outer join HPBA900T_TBL b on a.cmpycd   = b.cmpycd
                           and a.err_type  = b.CODE
                           and b.CDGBN    = '840'
                           and b.REMARK   = 'kor'
 where a.cmpycd     = #{cmpycd}
   and a.insp_req_dt = #{insp_req_dt}
   and a.insp_req_no = #{insp_req_no}
   and a.insp_gb     = #{insp_gb}
   and a.linecd      = #{linecd}
   and a.progcd		 = #{progcd}
   and a.ordymd		 = #{ordymd}
   and a.proymd		 = #{proymd}
   and a.lotno		 = #{lotno}
   and a.itemcd	 = #{itemcd}
   and a.insp_ord    = #{insp_ord}
   and a.inspcd     = #{inspcd}
 order by a.insp_ser

select RIGHT('00' + CAST(ISNULL(MAX(insp_ser), 0) + 1 AS VARCHAR), 3)
  from pd_insp_rslt_d
 where cmpycd	   = #{cmpycd}
   and insp_gb	   = #{insp_gb}
   and insp_req_dt = #{insp_req_dt}
   and insp_req_no = #{insp_req_no}
   and linecd	   = #{linecd}
   and progcd	   = #{progcd}
   and ordymd 	   = #{ordymd}
   and proymd 	   = #{proymd}
   and lotno	   = #{lotno}
   and itemcd	   = #{itemcd}
   and insp_ord	   = #{insp_ord}
   and inspcd	   = #{inspcd}

